def sanitize_identifier(identifier):
    allowed_chars = set('abcdefghijklmnopqrstuvwxyz_0123456789')
    return ''.join(c for c in identifier.lower() if c in allowed_chars)


def build_search_query(search_input, entity_type, table_name, searchable_fields):
    query_text = search_input['query']
